VALUES
  ('diplomatic-4dfbb1fb-moex-00072', 'diplomatic-4dfbb1fb', 'diplomatic-4dfbb1fb-moex-114-7f4830a9', 'sub-diplomatic-4dfbb1fb-04', NULL, 'single_choice', '1856年克里米亞戰爭結束，列強召開巴黎和會，關於戰後的和平，下列敘述何者錯誤？', '["多瑙河航行自由化", "黑海中立化、軍艦不得隨意進出兩海峽", "同意讓土耳其成為歐洲社會的一員", "敵船上的中立國貨物得予以沒入並充公"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:39+00:00", "source_pdf_sha1": "9acfd86bc501", "answer_pdf_sha1": "57309a558f15", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-義大利文組"}'::jsonb, NULL),
  ('diplomatic-4dfbb1fb-moex-00073', 'diplomatic-4dfbb1fb', 'diplomatic-4dfbb1fb-moex-114-7f4830a9', 'sub-diplomatic-4dfbb1fb-04', NULL, 'single_choice', '1899年9月美國國務卿海約翰（JohnHay）對美國駐英、德、日、俄等國大使發出訓令，命各大 使向駐在國爭取支持對華門戶開放政策，那個國家回應得最冷淡？', '["俄國", "英國", "日本", "德國"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:39+00:00", "source_pdf_sha1": "9acfd86bc501", "answer_pdf_sha1": "57309a558f15", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-義大利文組"}'::jsonb, NULL),
  ('diplomatic-4dfbb1fb-moex-00074', 'diplomatic-4dfbb1fb', 'diplomatic-4dfbb1fb-moex-114-7f4830a9', 'sub-diplomatic-4dfbb1fb-04', NULL, 'single_choice', '關於鴉片戰爭，下列敘述何者正確？', '["英國方面重視商務問題，早在乾隆年間，便已派遣阿美士德（William Pitt Amherst, 1st Earl Amherst）前來交涉", "由於自由主義貿易理論盛行，英國在清朝道光年間，把「東印度公司」對中國貿易的特權取消， 開始准許英商自由東來貿易", "林則徐在廣州禁煙，正值英國自由黨（TheLiberalParty）執政，首相巴麥尊（HenryJohnTemple Palmerston）決定出兵", "鴉片戰爭的結果，最後在道光22年（1842年）簽訂了《中英北京條約》"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:39+00:00", "source_pdf_sha1": "9acfd86bc501", "answer_pdf_sha1": "57309a558f15", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-義大利文組"}'::jsonb, NULL),
  ('diplomatic-4dfbb1fb-moex-00075', 'diplomatic-4dfbb1fb', 'diplomatic-4dfbb1fb-moex-114-7f4830a9', 'sub-diplomatic-4dfbb1fb-04', NULL, 'single_choice', '關於清朝末年中法越南戰爭，下列敘述何者正確？', '["同治年間，法國殖民者已實際控制越南中南部", "清廷內部分為和、戰兩派，李鴻章積極主戰", "光緒10年（1884年），法國艦隊炮擊基隆、封鎖臺灣，當時負責臺灣軍務的是沈葆楨", "光緒11年（1885年），劉永福率領黑旗軍，於廣西鎮南關、越北諒山等地，連戰皆捷"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:39+00:00", "source_pdf_sha1": "9acfd86bc501", "answer_pdf_sha1": "57309a558f15", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-義大利文組"}'::jsonb, NULL),
  ('diplomatic-4dfbb1fb-moex-00076', 'diplomatic-4dfbb1fb', 'diplomatic-4dfbb1fb-moex-114-7f4830a9', 'sub-diplomatic-4dfbb1fb-04', NULL, 'single_choice', '關於義和團之亂與八國聯軍，下列敘述何者正確？', '["義和團源自白蓮教，最早流行於河南一帶", "義和團的活動，一度引起德國的抗議，清廷乃派袁世凱南來，認真督剿", "八國聯軍出兵後，共推俄國將領瓦德西（AlfredvonWaldersee）為聯軍統帥", "八國聯軍占領北京後，東南各省督撫提倡「自保」運動，以曾國藩為首領銜"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:39+00:00", "source_pdf_sha1": "9acfd86bc501", "answer_pdf_sha1": "57309a558f15", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-義大利文組"}'::jsonb, NULL),
  ('diplomatic-4dfbb1fb-moex-00077', 'diplomatic-4dfbb1fb', 'diplomatic-4dfbb1fb-moex-114-7f4830a9', 'sub-diplomatic-4dfbb1fb-04', NULL, 'single_choice', '第一次鴉片戰爭中國戰敗，1842年8月，中英簽訂南京條約，其中所謂「五口通商」，並不包括：', '["溫州", "廣州", "廈門", "寧波"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:39+00:00", "source_pdf_sha1": "9acfd86bc501", "answer_pdf_sha1": "57309a558f15", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-義大利文組"}'::jsonb, NULL),
  ('diplomatic-4dfbb1fb-moex-00078', 'diplomatic-4dfbb1fb', 'diplomatic-4dfbb1fb-moex-114-7f4830a9', 'sub-diplomatic-4dfbb1fb-04', NULL, 'single_choice', '拿破崙（BonaparteNapoleon）領導的法蘭西第一帝國與歐洲反拿破崙同盟對抗，史稱「拿破崙戰 爭」。拿破崙如何稱呼他對付英國的戰略架構？', '["歐陸體系", "巴黎體系", "大陸體系", "北海體系"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:39+00:00", "source_pdf_sha1": "9acfd86bc501", "answer_pdf_sha1": "57309a558f15", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-義大利文組"}'::jsonb, NULL),
